export default function SkillIcon({ name }: { name: string }) {
  const icon = iconMap[name]
  if (!icon) return null
  return (
    <svg
      role="img"
      viewBox="0 0 24 24"
      className="w-4 h-4 shrink-0"
      aria-label={name}
    >
      <path d={icon.path} fill={`#${icon.hex}`} />
    </svg>
  )
}
